  ('retired-7ec62a85-moex-00033', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '關於比例原則，下列敘述何者錯誤？', '["國家雖為實現公益亦不得過度侵害基本人權", "有多種同樣能達成目的之手段時，國家應選擇最能達成目的之手段", "國家所採取之手段侵害人民權益愈重大，其所擬實現之公益目的亦須愈重大", "國家所採取之手段如反而有害公益目的之達成，則違反比例原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00034', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '甲與乙口頭約定，甲將自己的H屋租予乙居住，乙每月付租金2萬元，租期2年。甲、乙間有何種 民事契約關係？', '["2年定期租賃", "1年定期租賃", "不定期限租賃", "無效租賃"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00035', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '下列何者非法律明文規定得不給予當事人陳述意見之情形？', '["情況急迫，如予陳述意見之機會，顯然違背公益者", "行政機關已先命處分相對人限期改善", "受法定期間之限制，如予陳述意見之機會，顯然不能遵行者", "限制自由或權利之內容及程度，顯屬輕微，而無事先聽取相對人意見之必要者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00036', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '我國法律採取公、私法二元主義，下列敘述何者正確？', '["國家賠償係由普通法院審理，因此係屬私法關係", "軍事學校學生領取國家公費，係屬私法上金錢給付關係", "中央健康保險署與特約醫院間之特約關係屬公法關係", "國民住宅之承購契約為行政契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00037', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '依憲法訴訟法規定，關於憲法法庭之裁判，下列敘述何者錯誤？', '["判決，除別有規定外，應經大法官現有總額3分之2以上參與評議，大法官現有總額過半數同意", "裁定，除別有規定外，應經大法官現有總額過半數參與評議，參與大法官過半數同意", "聲請案件之受理，除別有規定外，應經大法官現有總額3分之2以上參與評議，參與大法官過半 數同意", "不受理之裁定得免附理由，但應記載參與裁定之大法官姓名及其同意與不同意之意見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00038', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '依憲法訴訟法規定，關於大法官迴避制度，下列敘述何者錯誤？', '["大法官於執行律師業務期間，其同一事務所律師為該聲請案件之訴訟代理人者，應自行迴避", "當事人認為大法官執行職務有偏頗之虞，得向憲法法庭聲請迴避", "除法定迴避事由外，大法官認有自行迴避之必要者，得經審判長同意迴避之", "依法迴避之大法官，不計入現有總額之人數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00039', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '關於保證人與債權人之關係，下列敘述何者錯誤？', '["保證人不得拋棄先訴抗辯權", "主債務人所有之抗辯，保證人得主張之", "保證人原則上得主張先訴抗辯權", "保證人得以主債務人對債權人之債權，主張抵銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
